      display: flex;
      flex-direction: column;
      gap: 3px;
    }
    /* 移动端滚动条样式（由JS动态开启） */
    #${ID} .menu-list.scrollable {
      overflow-y: auto;
      scrollbar-width: thin;
      scrollbar-color: rgba(170,120,255,0.3) transparent;
    }
    #${ID} .menu-list.scrollable::-webkit-scrollbar { width: 4px; }
    #${ID} .menu-list.scrollable::-webkit-scrollbar-track { background: transparent; }
    #${ID} .menu-list.scrollable::-webkit-scrollbar-thumb {
      background: rgba(170,120,255,0.3);
