      position: relative;
      transition: background 0.18s, box-shadow 0.18s;
      background: transparent;
    }
    /* 中间分隔线 */
    #${ID} .sexy-seg + .sexy-seg {
      border-left: 1px solid rgba(170,120,255,0.15);
    }
    #${ID} .sexy-seg:hover {
      background: rgba(120,70,220,0.15);
    }
    #${ID} .sexy-seg:active {
      transform: scale(0.97);
    }

    #${ID} .sexy-seg-label {
      font-size: 12px;
      color: rgba(255,255,255,0.82);
      letter-spacing: 0.02em;
      text-align: center;
      line-height: 1.3;
      transition: color 0.18s, text-shadow 0.18s;
      white-space: normal;
      word-break: keep-all;
    }
    #${ID} .sexy-seg-desc {
      font-size: 10px;
      color: rgba(210,190,255,0.55);
      letter-spacing: 0.02em;
      text-align: center;
      line-height: 1.2;
      transition: color 0.18s;
    }

    /* 点亮态 */
    #${ID} .sexy-seg.is-on {
      background: rgba(220,50,110,0.18);
      box-shadow: inset 0 0 18px rgba(255,60,130,0.1);
    }
    #${ID} .sexy-seg.is-on .sexy-seg-label {
      color: rgba(255,190,220,0.98);
      text-shadow: 0 0 8px rgba(255,90,155,0.55);
    }
    #${ID} .sexy-seg.is-on .sexy-seg-desc {
      color: rgba(255,160,200,0.55);
    }
    /* 点亮时加一条底部高亮线 */
    #${ID} .sexy-seg.is-on::after {
      content: '';
      position: absolute;
      bottom: 0; left: 10%; right: 10%;
      height: 2px;
      border-radius: 2px;
      background: linear-gradient(90deg, transparent, rgba(255,80,150,0.7), transparent);
    }

    #${ID} .menu-item-text {
      font-size: 14px;
      color: rgba(255,255,255,0.92);
      letter-spacing: 0.04em;
      line-height: 1.3;
      transition: color 0.2s, text-shadow 0.2s;
    }
    #${ID} .menu-item-desc {
      font-size: 11px;
      color: rgba(210,185,255,0.6);
      margin-top: 1px;
      letter-spacing: 0.02em;
      transition: color 0.2s;
    }

    /* 分割线 */
    #${ID} .menu-hr {
      height: 1px;
      margin: 2px 6px;
      background: linear-gradient(90deg, transparent, rgba(170,120,255,0.18) 30%, rgba(170,120,255,0.18) 70%, transparent);
    }

    /* 底栏 */
    #${ID} .menu-foot {
      padding: 5px 12px;
      font-size: 10px;
      letter-spacing: 0.1em;
      color: rgba(170,130,255,0.25);
      text-align: right;
      border-top: 1px solid rgba(170,120,255,0.07);
      border-radius: 0 0 12px 12px;
      flex-shrink: 0;
    }

    /* toggle-led 指示灯 */
    #${ID} .toggle-led {
      width: 8px; height: 8px;
      border-radius: 50%;
      flex-shrink: 0;
      background: rgba(90,70,110,0.5);
      border: 1px solid rgba(160,110,200,0.22);
      transition: all 0.25s ease;
      margin-left: auto;
    }
    #${ID} .menu-item-toggle.is-on .toggle-led {
      background: radial-gradient(circle at 38% 32%, #ffb3d4, #e0185e);
      box-shadow: 0 0 7px rgba(255,60,130,0.9), 0 0 16px rgba(255,60,130,0.45);
      border-color: rgba(255,130,175,0.7);
    }
    #${ID} .menu-item-toggle {
      display: flex;
      align-items: center;
      gap: 9px;
      padding: 9px 11px;
      border-radius: 10px;
      border: 1px solid rgba(170,120,255,0.22);
      cursor: pointer;
      transition: all 0.2s ease;
      background: rgba(20,14,36,0.6);
      margin: 2px 6px;
    }
    #${ID} .menu-item-toggle:hover {
      background: rgba(120,70,220,0.18);
      border-color: rgba(170,120,255,0.45);
    }
    #${ID} .menu-item-toggle.is-on {
      background: rgba(220,50,110,0.14);
      border-color: rgba(255,90,155,0.38);
    }
    #${ID} .menu-item-toggle.is-on .menu-item-text {
      color: rgba(255,185,215,0.96);
      text-shadow: 0 0 8px rgba(255,90,155,0.5);
    }

    /* 入场 */
    @keyframes orb-in {
      from { opacity:0; transform: scale(0.75); }
      to   { opacity:1; transform: scale(1); }
    }
    #${ID} { animation: orb-in 0.3s cubic-bezier(0.34,1.3,0.64,1) both; }
  `;
  pdoc.head.appendChild(style);

  // ── DOM ──────────────────────────────────────────────────
  const root = pdoc.createElement('div');
  root.id = ID;
  root.style.left = pos.x + 'px';
  root.style.top  = pos.y + 'px';

  root.innerHTML = `
    <div class="orb-ring"></div>
    <div class="orb" id="${ID}-orb">
      <span class="orb-icon">✦</span>
    </div>

    <div class="menu" id="${ID}-menu">
      <div class="menu-shell">
        <div class="menu-head" id="${ID}-head">
          <div class="menu-gem"></div>
          <div class="menu-title">TGbreak</div>
          <button class="menu-close" id="${ID}-close">✕</button>
        </div>

        <div class="menu-list">

          <!-- 色色三档融合控件 -->
          <div class="sexy-title">色色程度</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-sexy-l">
              <div class="sexy-seg-label">轻度</div>
              <div class="sexy-seg-desc">瑟瑟描述</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-sexy-m">
              <div class="sexy-seg-label">中度</div>
              <div class="sexy-seg-desc">够用了</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-sexy-h">
              <div class="sexy-seg-label">重度</div>
              <div class="sexy-seg-desc">记得关掉</div>
            </div>
          </div>

          <div class="sexy-title">不抢话设置</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-talk-l">
              <div class="sexy-seg-label">轻度</div>
              <div class="sexy-seg-desc">多字数</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-talk-m">
              <div class="sexy-seg-label">中度</div>
              <div class="sexy-seg-desc">少字数</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-talk-h">
              <div class="sexy-seg-label">重度</div>
              <div class="sexy-seg-desc">超级防抢</div>
            </div>
          </div>

          <div class="sexy-title">人称设置</div>
          <div class="sexy-group">
            <div class="sexy-seg" id="${ID}-item-pov-1">
              <div class="sexy-seg-label">第一人称</div>
              <div class="sexy-seg-desc">我/我的</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pov-2">
              <div class="sexy-seg-label">第二人称</div>
              <div class="sexy-seg-desc">你/你的</div>
            </div>
            <div class="sexy-seg" id="${ID}-item-pov-3">
              <div class="sexy-seg-label">第三人称</div>
              <div class="sexy-seg-desc">他/她/它</div>
            </div>
          </div>

          <div class="sexy-title">大总结</div>
          <div class="menu-item-toggle" id="${ID}-item-summary">
            <div style="flex:1;min-width:0;">
              <div class="menu-item-text">大总结</div>
              <div class="menu-item-desc">切换总结模式</div>
            </div>
            <div class="toggle-led"></div>
          </div>

          <div class="sexy-title">预设检查更新</div>
          <div class="menu-item" id="${ID}-item-update">
            <div>
              <div class="menu-item-text">检查更新</div>
              <div class="menu-item-desc">点击查看最新动态</div>
            </div>
          </div>

        </div>

        <div class="menu-foot">TAVERN HELPER · PANEL</div>
      </div>
    </div>
  `;

  // 挂到 <html> 根节点而非 body，避免 body 上的 transform 导致 fixed 定位参照系错误
  (pdoc.documentElement || pdoc.body).appendChild(root);

  // 移动端 100vh 不准确，用 JS 设置真实视口高度变量
  function setVH() {
    const vh = pwin.innerHeight * 0.01;
    pdoc.documentElement.style.setProperty('--vh', `${vh}px`);
    // 移动端：给 menu-list 加 scrollable class + 限制 max-height
    // PC端：完全不动 menu-list，保持原始状态
    const menuList = pdoc.getElementById(ID)?.querySelector('.menu-list');
    if (!menuList) return;
    const isMobileNow = pwin.innerWidth <= 768;
    if (isMobileNow) {
      menuList.classList.add('scrollable');
      menuList.style.maxHeight = `${pwin.innerHeight * 0.5}px`;
    } else {
      menuList.classList.remove('scrollable');
      menuList.style.maxHeight = '';
    }
  }
  setVH();
  pwin.addEventListener('resize', setVH);

  // ── 元素引用 ──────────────────────────────────────────────
  const orb      = pdoc.getElementById(`${ID}-orb`);
  const head     = pdoc.getElementById(`${ID}-head`);
  const btnClose = pdoc.getElementById(`${ID}-close`);
  const menu     = pdoc.getElementById(`${ID}-menu`);
  let isOpen = false;

  function isPromptEnabled(li) {
    return !li.classList.contains('completion_prompt_manager_prompt_disabled');
  }

  function clickToggle(li) {
    const btn = li.querySelector('.prompt-manager-toggle-action');
    if (btn) btn.click();
  }

  // ── 色色单选档位配置 ─────────────────────────────────────
  const sexyLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-l`),
      label:   '色色(轻度)',
      turnOn:  ['瑟瑟描述'],
      turnOff: ['深度瑟瑟', '超级瑟瑟视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-m`),
      label:   '色色(中度)',
      turnOn:  ['瑟瑟描述', '深度瑟瑟'],
      turnOff: ['超级瑟瑟视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-h`),
      label:   '色色(重度)',
      turnOn:  ['瑟瑟描述', '深度瑟瑟', '超级瑟瑟视角'],
      turnOff: [],
    },
  ];

  function findByKeyword(keyword) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).filter(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      const idx = name.indexOf(keyword);
      if (idx === -1) return false;
      const before = idx > 0 ? name[idx - 1] : null;
      const after  = idx + keyword.length < name.length ? name[idx + keyword.length] : null;
      const isCJKorAlnum = c => c && /[\u4e00-\u9fff\w]/.test(c);
      return !isCJKorAlnum(before) && !isCJKorAlnum(after);
    });
  }

  function ensureOn(keyword) {
    findByKeyword(keyword).forEach(li => {
      if (!isPromptEnabled(li)) clickToggle(li);
    });
  }

  function ensureOff(keyword) {
    findByKeyword(keyword).forEach(li => {
      if (isPromptEnabled(li)) clickToggle(li);
    });
  }

  let sexyActive = -1;
  let talkActive = -1;

  function applyLevels(levels, activeIdx, setActive) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { toastr.warning('请先打开预设管理面板'); return; }

    if (activeIdx === -1) {
      const allKw = new Set(levels.flatMap(l => [...l.turnOn, ...l.turnOff]));
      allKw.forEach(kw => ensureOff(kw));
      levels.forEach(({ el }) => el.classList.remove('is-on'));
      setActive(-1);
    } else {
      const { turnOn, turnOff, label } = levels[activeIdx];
      turnOn.forEach(kw => ensureOn(kw));
      turnOff.forEach(kw => ensureOff(kw));
      levels.forEach(({ el }, i) => el.classList.toggle('is-on', i === activeIdx));
      setActive(activeIdx);
      toastr.success(`已切换到 ${label}`);
    }
  }

  sexyLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = sexyActive === idx ? -1 : idx;
      if (next === -1) toastr.info('色色已全部关闭');
      applyLevels(sexyLevels, next, v => sexyActive = v);
    });
  });

  const talkLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-talk-l`),
      label:   '不抢话(轻度)',
      turnOn:  ['防抢话', '多字数设定'],
      turnOff: ['超级防抢话', '少字数设定'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-talk-m`),
      label:   '不抢话(中度)',
      turnOn:  ['防抢话', '少字数设定'],
      turnOff: ['超级防抢话', '多字数设定'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-talk-h`),
      label:   '不抢话(重度)',
      turnOn:  ['防抢话', '超级防抢话', '少字数设定'],
      turnOff: ['多字数设定'],
    },
  ];

  talkLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = talkActive === idx ? -1 : idx;
      if (next === -1) {
        const list = pdoc.querySelector('#completion_prompt_manager_list');
        if (!list) { toastr.warning('请先打开预设管理面板'); return; }
        ensureOn('多字数设定');
        ensureOff('防抢话');
        ensureOff('超级防抢话');
        ensureOff('少字数设定');
        talkLevels.forEach(({ el }) => el.classList.remove('is-on'));
        talkActive = -1;
        toastr.info('不抢话已关闭，多字数设定已开启');
        return;
      }
      applyLevels(talkLevels, next, v => talkActive = v);
    });
  });


  // ── 人称设置档位 ─────────────────────────────────────────
  const povLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-pov-1`),
      label:   '第一人称',
      turnOn:  ['第一人称视角'],
      turnOff: ['第二人称视角', '第三人称视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-pov-2`),
      label:   '第二人称',
      turnOn:  ['第二人称视角'],
      turnOff: ['第一人称视角', '第三人称视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-pov-3`),
      label:   '第三人称',
      turnOn:  ['第三人称视角'],
      turnOff: ['第一人称视角', '第二人称视角'],
    },
  ];

  let povActive = -1;

  povLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = povActive === idx ? -1 : idx;
      if (next === -1) toastr.info('人称设置已关闭');
      applyLevels(povLevels, next, v => povActive = v);
    });
  });

  // ── 大总结按钮 ───────────────────────────────────────────
  let summaryActive = false;
  let summaryBottomItemName = null;

  const itemSummary = pdoc.getElementById(`${ID}-item-summary`);

  function getSummaryBottomItem() {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return null;
    const items = Array.from(list.querySelectorAll('li[data-pm-identifier]'));
    for (const li of items) {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      if (name.includes('模型--底部') && isPromptEnabled(li)) {
        return name;
      }
    }
    return null;
  }

  function findByExactName(fullName) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return null;
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).find(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      return name === fullName;
    }) ?? null;
  }

  itemSummary.addEventListener('click', () => {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { toastr.warning('请先打开预设管理面板'); return; }

    if (!summaryActive) {
      summaryBottomItemName = getSummaryBottomItem();
      if (summaryBottomItemName) {
        console.log(`[大总结] 记录底部项目: "${summaryBottomItemName}"`);
        const liBottom = findByExactName(summaryBottomItemName);
        if (liBottom && isPromptEnabled(liBottom)) clickToggle(liBottom);
      } else {
        console.warn('[大总结] 未找到已开启的"模型--底部"项目');
      }
      ensureOn('大总结之术');
      summaryActive = true;
      itemSummary.classList.add('is-on');
      toastr.success('大总结已开启');

    } else {
      ensureOff('大总结之术');
      if (summaryBottomItemName) {
        const li = findByExactName(summaryBottomItemName);
        if (li && !isPromptEnabled(li)) {
          clickToggle(li);
          console.log(`[大总结] 已恢复: "${summaryBottomItemName}"`);
        }
      } else {
        console.warn('[大总结] 无记录，无法恢复底部项目');
        toastr.warning('无法恢复底部项目，请手动开启');
      }
      summaryActive = false;
      summaryBottomItemName = null;
      itemSummary.classList.remove('is-on');
      toastr.info('大总结已关闭');
    }
  });

  // ── 检查更新按钮 ──────────────────────────────────────────
  pdoc.getElementById(`${ID}-item-update`).addEventListener('click', () => {
    toastr.info('尽情期待，如果喜欢我的预设\n请多来我的dc帖子聊天吹水。', '', { timeOut: 8000 });
  });

  // ── 检查某关键字对应的预设项是否全部开启 ──────────────────
  function isKeywordOn(keyword) {
    const items = findByKeyword(keyword);
    // 找不到该关键字对应的项，视为关闭
    if (items.length === 0) return false;
    return items.every(li => isPromptEnabled(li));
  }

  // ── 检测某档位是否匹配当前预设状态 ──────────────────────────
  // turnOn 里的关键字全部开启 && turnOff 里的关键字全部关闭 → 匹配
  function detectLevel(levels) {
    for (let i = 0; i < levels.length; i++) {
      const { turnOn, turnOff } = levels[i];
      const onMatch  = turnOn.every(kw => isKeywordOn(kw));
      const offMatch = turnOff.every(kw => !isKeywordOn(kw));
      if (onMatch && offMatch) return i;
    }
    return -1;
  }

  // ── 初始化时读取预设状态，自动高亮对应档位 ──────────────────
  function initDetectState() {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return; // 预设面板未打开，无法检测，跳过
    sexyActive = detectLevel(sexyLevels);
    talkActive = detectLevel(talkLevels);
    povActive  = detectLevel(povLevels);
    // 大总结：检测"大总结之术"是否开启
    const summaryOn = isKeywordOn('大总结之术');
    if (summaryOn) {
      summaryActive = true;
      itemSummary.classList.add('is-on');
    }
    syncAllToggleBtns();
  }

  // ── 同步所有开关按钮状态 ─────────────────────────────────
  function syncAllToggleBtns() {
    sexyLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === sexyActive));
    talkLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === talkActive));
    povLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === povActive));
  }

  // 1200ms 首次检测，2000ms 兜底再试一次
  let initDone = false;
  function tryInitDetect() {
    if (initDone) return;
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (list) {
      initDone = true;
      initDetectState();
    }
  }
  setTimeout(tryInitDetect, 1200);
  setTimeout(tryInitDetect, 2000);

  // ── 展开/收起 ────────────────────────────────────────────
  function updateMenuDirection() {
    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const menuH = 420; // 菜单估算最大高度

    // 左右方向
    if (orbX < pwin.innerWidth / 2) {
      menu.style.left  = '0';
      menu.style.right = 'auto';
    } else {
      menu.style.left  = 'auto';
      menu.style.right = '0';
    }

    // 上下方向：下方空间不够就往上弹
    const spaceBelow = pwin.innerHeight - orbY - 60;
    if (spaceBelow < menuH && orbY > menuH / 2) {
      // 往上弹
      menu.style.top    = 'auto';
      menu.style.bottom = '58px';
      root.classList.add('open-up');
      if (orbX < pwin.innerWidth / 2) {
        menu.style.transformOrigin = 'bottom left';
      } else {
        menu.style.transformOrigin = 'bottom right';
      }
    } else {
      // 往下弹（默认）
      menu.style.top    = '58px';
      menu.style.bottom = 'auto';
      root.classList.remove('open-up');
      if (orbX < pwin.innerWidth / 2) {
        menu.style.transformOrigin = 'top left';
      } else {
        menu.style.transformOrigin = 'top right';
      }
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) {
      updateMenuDirection();
      syncAllToggleBtns();
    } else {
      root.classList.remove('open-up');
    }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }

  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  // ── 保存位置 ──────────────────────────────────────────────
  function savePos() {
    try {
      insertOrAssignVariables({
        orbV2_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top) })
      }, { type: 'global' });
    } catch (_) {}
  }

  // ── 拖拽（鼠标）──────────────────────────────────────────
  let drag = false, ox = 0, oy = 0, moved = false;

  let dragMask = null;
  function createMask() {
    dragMask = parent.document.createElement('div');
    dragMask.style.cssText = [
      'position:fixed', 'inset:0', 'z-index:2147483646',
      'cursor:grabbing', 'background:transparent',
    ].join(';');
    parent.document.body.appendChild(dragMask);
  }
  function removeMask() {
    dragMask?.remove();
    dragMask = null;
  }

  function startDrag(cx, cy) {
    drag = true; moved = false;
    const rect = root.getBoundingClientRect();
    ox = cx - rect.left;
    oy = cy - rect.top;
    root.style.transition = 'none';
    createMask();
  }
  function moveDrag(cx, cy) {
    if (!drag) return;
    moved = true;
    root.style.left = Math.max(4, Math.min(cx - ox, pwin.innerWidth  - 56)) + 'px';
    root.style.top  = Math.max(4, Math.min(cy - oy, pwin.innerHeight - 56)) + 'px';
  }
  function endDrag() {
    if (!drag) return;
    drag = false;
    root.style.transition = '';
    removeMask();
    if (moved) savePos();
  }

  orb.addEventListener('mousedown', e => { startDrag(e.clientX, e.clientY); e.preventDefault(); });
  head.addEventListener('mousedown', e => {
    if (e.target.id === `${ID}-close`) return;
    startDrag(e.clientX, e.clientY); e.preventDefault();
  });
  parent.document.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
  parent.document.addEventListener('mouseup', () => endDrag());

  orb.addEventListener('click', e => {
    if (moved) { moved = false; return; }
    toggle();
  });

  // ── 拖拽（触摸）──────────────────────────────────────────
  // 只在 orb 本身监听 touch，不挂全局 pdoc，避免菜单内触摸被误拦截

  orb.addEventListener('touchstart', e => {
    const t = e.touches[0];
    startDrag(t.clientX, t.clientY);
    e.stopPropagation();
  }, { passive: true });

  orb.addEventListener('touchmove', e => {
    if (!drag) return;
    const t = e.touches[0];
    moveDrag(t.clientX, t.clientY);
  }, { passive: true });

  orb.addEventListener('touchend', e => {
    const wasMoved = moved;
    endDrag();
    if (!wasMoved) toggle();
    e.stopPropagation();
    e.preventDefault(); // 阻止后续 click 事件触发
  }, { passive: false });

  // head 拖拽触摸
  head.addEventListener('touchstart', e => {
    if (e.target.id === `${ID}-close`) return;
    const t = e.touches[0];
    startDrag(t.clientX, t.clientY);
    e.stopPropagation();
  }, { passive: true });

  head.addEventListener('touchmove', e => {
    if (!drag) return;
    const t = e.touches[0];
    moveDrag(t.clientX, t.clientY);
  }, { passive: true });

  head.addEventListener('touchend', e => {
    endDrag();
    e.stopPropagation();
  }, { passive: true });

  // 全局 touchmove 只用于拖拽中跟踪位置（鼠标拖拽用）
  // 触摸拖拽已在 orb/head 上处理，这里不重复注册

  // ── 预设切换自动销毁 ─────────────────────────────────────
  // ST 的 completion preset 下拉框 id 固定为 settings_preset_openai
  // 直接监听它的 change 事件，触发即销毁悬浮窗，简单可靠。

  // 脚本失效（预设切换）时，window 会被销毁，触发 pagehide/unload。
  // 在此时删除挂在 pdoc 上的悬浮窗，实现自动清理。
  window.addEventListener('pagehide', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });
  window.addEventListener('unload', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });

}));
